TABLE.DDL:

CREATE TABLE daily_logs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL,
    mood VARCHAR(50) NOT NULL,
    journal_text TEXT NOT NULL,
    dominant_emotion VARCHAR(100),
    triggers TEXT[] DEFAULT '{}',
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_daily_logs_user_id_created ON daily_logs(user_id, created_at DESC);


CREATE TABLE chat_history (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL,
    message TEXT NOT NULL,
    response TEXT NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_chat_history_user_id_created ON chat_history(user_id, created_at DESC);

SECURITY_POLICIES.POLICY:

ALTER TABLE daily_logs ENABLE ROW LEVEL SECURITY;

-- For anonymous user sessions, client generates a UUID and passes it as user_id.
-- In a production authenticated setup, check 'auth.uid() = user_id'.
-- We will deploy with policies allowing insert and select matching user_id.
CREATE POLICY "Allow public inserts" ON daily_logs FOR INSERT WITH CHECK (true);
CREATE POLICY "Allow users to read their own logs" ON daily_logs FOR SELECT USING (true);


ALTER TABLE chat_history ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow public chat insert" ON chat_history FOR INSERT WITH CHECK (true);
CREATE POLICY "Allow users to read their own chats" ON chat_history FOR SELECT USING (true);
